import '../lib/asset.dart';
import '../lib/asset_cache.dart';
import '../lib/recency_index.dart';

void check(bool condition, String message) {
  if (!condition) throw StateError(message);
}

void main() {
  final index = RecencyIndex()..record('a')..record('b')..record('a');
  check(index.keys.join(',') == 'b,a', 'recording an existing key refreshes order');

  final cache = AssetCache(2);
  cache.put('a', Asset('1', <int>[1]));
  cache.put('b', Asset('1', <int>[2]));
  check(cache.get('a') != null, 'read returns the asset');
  cache.put('c', Asset('1', <int>[3]));
  check(cache.get('a') != null && cache.get('b') == null, 'read refresh controls eviction');
  print('feedback tests passed');
}
